const data = $input.first().json.data || {};
const token = $('Webhook GET').first().json.query?.token || '';
const N8N = 'https://n8n-n8n.zzeluw.easypanel.host';
const html = `<!DOCTYPE html>
<html lang="es"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>ArquitAI Concierge - ${data.project_name || 'Tu proyecto'}</title>
<style>
* { box-sizing: border-box; }
body { font-family: 'Segoe UI', Arial, sans-serif; margin: 0; padding: 20px; background: #f3f4f6; color: #2c3e50; }
.container { max-width: 720px; margin: 0 auto; background: white; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,0.08); overflow: hidden; }
.header { background: #2c3e50; color: white; padding: 20px; }
.header h1 { margin: 0; font-size: 20px; }
.header p { margin: 6px 0 0; opacity: 0.85; font-size: 14px; }
.body { padding: 20px; }
.history { max-height: 400px; overflow-y: auto; margin-bottom: 20px; padding: 10px; background: #f9fafb; border-radius: 6px; }
.msg { padding: 10px 14px; border-radius: 12px; margin-bottom: 10px; max-width: 85%; }
.msg.user { background: #3498db; color: white; margin-left: auto; }
.msg.bot { background: #ecf0f1; color: #2c3e50; }
.msg.escalated { background: #e67e22; color: white; }
.msg.bot small { display: block; opacity: 0.7; margin-top: 4px; font-size: 11px; }
.form { display: flex; gap: 10px; }
.form textarea { flex: 1; padding: 10px; border: 1px solid #d1d5db; border-radius: 6px; font-family: inherit; resize: vertical; min-height: 60px; }
.form button { background: #3498db; color: white; border: none; padding: 0 24px; border-radius: 6px; cursor: pointer; font-weight: bold; }
.form button:hover { background: #2980b9; }
.form button:disabled { background: #95a5a6; cursor: not-allowed; }
.footer { padding: 12px 20px; background: #f9fafb; border-top: 1px solid #e5e7eb; font-size: 12px; color: #7f8c8d; }
.empty { text-align: center; color: #95a5a6; padding: 40px 20px; }
</style></head><body>
<div class="container">
<div class="header">
<h1>${data.project_name || 'Tu proyecto'}</h1>
<p>Hola ${data.client_name || 'cliente'}, soy ArquitAI Concierge. Hazme cualquier pregunta sobre tu proyecto.</p>
</div>
<div class="body">
<div id="history" class="history"><div class="empty">Aun no has hecho preguntas. Pruebame con &quot;En que fase esta mi proyecto?&quot; o &quot;Cuando esta prevista la entrega?&quot;</div></div>
<form id="chatForm" class="form" onsubmit="return askQuestion(event)">
<textarea id="question" placeholder="Escribe tu pregunta aqui..." required></textarea>
<button type="submit" id="sendBtn">Enviar</button>
</form>
</div>
<div class="footer">Si tu pregunta requiere decision profesional, te conectaremos con el arquitecto. Las respuestas son automaticas y referenciales — confia siempre en la palabra final del arquitecto.</div>
</div>
<script>
const TOKEN = ${JSON.stringify(token)};
const API = ${JSON.stringify(N8N + '/webhook/client-ask')};
const history = document.getElementById('history');
let first = true;

async function askQuestion(e) {
  e.preventDefault();
  const ta = document.getElementById('question');
  const btn = document.getElementById('sendBtn');
  const q = ta.value.trim();
  if (!q) return false;
  if (first) { history.innerHTML = ''; first = false; }
  const u = document.createElement('div');
  u.className = 'msg user';
  u.textContent = q;
  history.appendChild(u);
  history.scrollTop = history.scrollHeight;
  ta.value = ''; btn.disabled = true; btn.textContent = '...';
  try {
    const res = await fetch(API, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({token: TOKEN, question: q})});
    const data = await res.json();
    const b = document.createElement('div');
    b.className = 'msg bot' + (data.escalated ? ' escalated' : '');
    b.innerHTML = (data.answer || 'Sin respuesta').replace(/\\n/g,'<br>') + (data.escalated ? '<small>El arquitecto recibe esta consulta y se pondra en contacto.</small>' : '');
    history.appendChild(b);
    history.scrollTop = history.scrollHeight;
  } catch (err) {
    const b = document.createElement('div');
    b.className = 'msg bot';
    b.textContent = 'Error de conexion. Intentalo de nuevo en un momento.';
    history.appendChild(b);
  } finally {
    btn.disabled = false; btn.textContent = 'Enviar';
  }
  return false;
}
</script></body></html>`;
return [{ json: { html: html } }];
